function renderIntersections() {
  const tbody = document.getElementById('i-table-body');
  INTERSECTIONS.forEach(i => {
    const tr = document.createElement('tr');
    const volumeClass = i.cites >= 3000 ? 'high' : i.cites >= 1000 ? 'med' : '';
    tr.innerHTML = `
      <td>
        <div class="i-name">${i.name}</div>
      </td>
      <td><span class="i-count ${volumeClass}">${i.cites.toLocaleString()}</span></td>
      <td style="font-size:13px;color:var(--muted);">${i.trend}</td>
      <td><span class="i-flag ${i.flag}">${i.flagText}</span></td>
    `;
    tbody.appendChild(tr);
  });
}
renderIntersections();

/* ── Copy-to-clipboard for letters ── */
document.querySelectorAll('[data-copy-target]').forEach(btn => {
  btn.addEventListener('click', async () => {
    const targetId = btn.dataset.copyTarget;
    const el = document.getElementById(targetId);
    if (!el) return;
    const text = el.innerText; // strips HTML, keeps line breaks

    const status = document.querySelector(`.copy-status[data-for="${targetId}"]`);
    try {
      await navigator.clipboard.writeText(text);
      if (status) {
        status.textContent = '✓ Copied to clipboard';
        status.classList.add('shown');
        document.getElementById('live-region').textContent = 'Letter copied to clipboard';
        setTimeout(() => {
          status.classList.remove('shown');
        }, 2600);
      }
    } catch (e) {
      if (status) {
        status.textContent = 'Copy failed — try selecting manually';
        status.classList.add('shown');
      }
    }
  });
});

/* ── Smooth-scroll TOC links with focus management ── */
document.querySelectorAll('.toc-link').forEach(link => {
  link.addEventListener('click', (e) => {
    const href = link.getAttribute('href');
    if (href && href.startsWith('#')) {
      const target = document.querySelector(href);
      if (target) {
        e.preventDefault();
        target.scrollIntoView({ behavior: 'smooth', block: 'start' });
        // Move focus to target for screen-reader users
        target.setAttribute('tabindex', '-1');
        target.focus({ preventScroll: true });
      }
    }
  });
});

